import { test, expect } from '@playwright/test';

test('Amazon SG backpack image loads', async ({ page }) => {
  // 1. Launch browser → Amazon SG
  await page.goto('https://www.amazon.sg/', { waitUntil: 'domcontentloaded' });

  // 2. Search for "backpack"
  const searchBox = page.getByRole('searchbox', { name: /search/i });
  await expect(searchBox).toBeVisible();
  await searchBox.fill('backpack');
  await page.locator('input#nav-search-submit-button[type="submit"]').click();

  // 3. Open first product
  await page.waitForSelector('div.s-main-slot');
  const firstProductLink = page.locator('div.s-main-slot a[href*="/dp/"]').first();
  await expect(firstProductLink).toBeVisible();
  await firstProductLink.click();

  // 4. Validate product image is loaded (img not broken)
  // Wait for main product image to appear (use unique id="landingImage")
  const productImage = page.locator('img#landingImage');
  await expect(productImage).toBeVisible();

  // Check image is loaded (not broken)
  const isImageLoaded = await productImage.evaluate((img: HTMLImageElement) => {
    return img.complete && img.naturalWidth > 0;
  });
  expect(isImageLoaded).toBeTruthy();

  // 5. Close browser (handled by Playwright test runner)
});
